import json

def validate_session_schema(session_attrs):
    required_keys = {'user_id', 'conversation_id', 'preferences'}
    schema_errors = []

    if not isinstance(session_attrs, dict):
        return False, ['Session attributes must be object']

    missing = required_keys - set(session_attrs.keys())
    if missing:
        schema_errors.append(f'Missing required keys: {missing}')

    # Check for string corruption
    for key, value in session_attrs.items():
        if isinstance(value, str) and len(value) > 10000:
            schema_errors.append(f'Key {key} exceeds size limit')

